var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗, 차가!","JPN":"あっ、つめたっ！","ENG":"Eep, it's cold!","TWN":"啊，好冰！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아직 해도 안 졌는데 뭘 꾸벅꾸벅 졸고 있어, 꼬맹이.","JPN":"まだ昼間なのになにウトウトしてんだ、ガキ。","ENG":"Why are you dosing off already, kid? The sun hasn't even set.","TWN":"太陽還沒下山呢，你怎麼就開始打瞌睡了，小鬼。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"캔커피야. 마셔. 오는 길에 자판기에서 뽑아 왔어.","JPN":"缶コーヒーだ、飲め。自販機で買ってきた。","ENG":"Here's a can of coffee. Drink it. I got it from a vending machine on the way.","TWN":"這是咖啡，喝吧。來的路上在自動販賣機買的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗, 고마워요! 언니!","JPN":"ありがとうございます、お姉ちゃん！","ENG":"Oh, thank you, Rita!","TWN":"啊，謝謝！姐姐！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우와, 엄청 달달하다...... 혀가 얼얼할 정도예요.","JPN":"うわぁ、すっごく甘い……舌がピリピリするくらいです。","ENG":"Wow, it's so sweet... My tongue almost feels numb.","TWN":"嗚哇，好甜啊……舌頭都麻麻的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 네 입맛에 어울릴 것 같더라.","JPN":"よかったな。お前の好みだろ。","ENG":"I know. I figured a sweet tooth like you would enjoy it.","TWN":"嗯。我就覺得你會喜歡。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"맞다! 저 엄청 이상한 꿈 꿨어요!","JPN":"そうだ！　私、とても変な夢をみました！","ENG":"Oh, right! I had the strangest dream!","TWN":"對了！我剛剛做了非常奇怪的夢！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꿈?","JPN":"夢？","ENG":"Dream?","TWN":"夢？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹! 그림자가 된 리타 언니를 쓰러뜨리고 원래대로 되돌리는 꿈이요!","JPN":"はい！　シャドウになったリタお姉ちゃんを倒して元に戻す夢です！","ENG":"Yup! You turned into a Shadow, but I defeated you to turn you back to normal!","TWN":"嗯！夢見打敗了變成暗影的麗塔姐姐，回到了現世的夢！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"도중에 부상 입은 언니를 챙기느라 엄청 고생도 하는 스펙타클한 여정이었어요!","JPN":"途中で負傷したお姉ちゃんをお世話したりして、とても苦労したスペクタクルな旅でしたよ！","ENG":"It was such a spectacular adventure! I even had to carry you around because you got wounded along the way!","TWN":"途中為了照顧受傷的姐姐，非常辛苦的壯烈旅程！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그러니까, 평소에 날 그렇게 한심한 눈으로 봤단 말이지.","JPN":"つまり、普段から私がそんな頼りない奴に見えてたってことか？","ENG":"So you've always thought of me as some helpless pathetic fool, huh?","TWN":"所以，你平時才用那麼慘兮兮的眼神看我啊。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹?! 아, 아뇨! 오해예요, 언니!","JPN":"え！？　ち、違いますよ！　それは誤解です！","ENG":"Huh?! N-no! I didn't mean anything like that!","TWN":"嗯？！啊，不是！你誤會了，姐姐！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"농담이야, 꼬맹이. 호들갑 떨지 마.","JPN":"冗談だ、ガキ。そんなに騒ぐな。","ENG":"I'm just messing with you, kid. Don't freak out.","TWN":"開玩笑的，小鬼。別大呼小叫的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"진짜로요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꿈 얘기로 화낼 만큼 치졸하진 않으니까.","JPN":"たかが夢の話で怒るほど器が小さい人じゃない。","ENG":"I'm not so narrow-minded that I'd get mad over some dream.","TWN":"我還不至於幼稚到因為那種夢話生氣。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그보다 오늘 약속 안 잊어 버렸지?","JPN":"それより、今日の約束は覚えているよな？","ENG":"Anyway, you didn't forget about our plans today, did you?","TWN":"話說回來，你沒忘記今天的約定吧？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"약속이라면......","JPN":"約束って……","ENG":"Plans?","TWN":"約定……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 맞다! 제 생일 지나면 언니 단골 술집 같이 가기로 했었죠?","JPN":"あ、そうだ！　私の誕生日が過ぎたら、お姉ちゃんの行きつけのバーに行くことにしましたよね！","ENG":"Oh, right! We were supposed to go to your favorite bar together after my birthday!","TWN":"啊，對了！之前說好我的生日過後，就一起去姐姐經常光顧的酒館對吧？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"분위기 좋은 곳이야. 꼬맹이 넌 어차피 가도 밀크 쉐이크나 먹겠지만.","JPN":"なかなか雰囲気のいいバーだ。ガキのお前はどうせバニラシェイクしか飲まないだろうが。","ENG":"It's got a nice vibe. Although I guess you'll just sip on milkshakes anyway.","TWN":"那裡氣氛很不錯。雖然你這個小鬼去了也只能喝奶昔。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헷. 언니 왠지 무지 기쁜 거 같아요.","JPN":"ヘヘッ。なんだかお姉ちゃん、とても嬉しそうにしていますね。","ENG":"Heh heh. You seem really excited.","TWN":"嘿嘿。姐姐好像很開心的樣子。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"시끄러워. 호라이즌 녀석은 술친구로 실격이니 그렇지.","JPN":"うるさい。今までホライズンが飲み友として使えなかったからだ。","ENG":"Oh, shut up. It's just because Horizon sucks as a drinking partner.","TWN":"閉嘴。都是因為地平線沒資格當我的酒友。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤......","JPN":"へへ……","ENG":"Heh heh...","TWN":"嘿嘿……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그런데 언니, 밖에 눈 와요?","JPN":"ところでお姉ちゃん。外で雪、降っていませんか？","ENG":"By the way, is it snowing outside?","TWN":"但是姐姐，外面下雪了嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"갑자기 무슨 소리야. 창밖이 저렇게 화창한데.","JPN":"急に何を言っているんだ。窓の外はあんなに晴れているのに。","ENG":"Don't be ridiculous. It's all sunny outside.","TWN":"你在說什麼，窗外那麼風和日麗。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하지만 그런 것치고는 너무......","JPN":"でもその割りにとても……","ENG":"But it's too...","TWN":"但是我怎麼覺得…"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"추워......","JPN":"寒い……","ENG":"... Cold...","TWN":"好冷……"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언...... 니......","JPN":"お姉……ちゃん……","ENG":"Ri... ta...","TWN":"姐……姐……"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"집에...... 가고 싶어......","JPN":"家に……帰りたい……","ENG":"I want... to go home...","TWN":"我想……回家……"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_NULL","text":{"KOREA":"그래, 우리 귀여운 동생. 내가 너를 너무 만신창이로 만들어 버렸지.","JPN":"そうだな、愛しい私のダッシュ。お前を相手にやりすぎたかもしれないな。","ENG":"Yes, my precious sister. I'm afraid I've torn you apart.","TWN":"好，我可愛的妹妹。我把你弄得遍體鱗傷了。"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_NULL","text":{"KOREA":"하지만 저항한 너에게도 책임이 있단다.","JPN":"でも抵抗したお前にも責任があるんだ。","ENG":"But it's partly your fault for resisting so much.","TWN":"但一直這樣抵抗的你也有責任。"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_NULL","text":{"KOREA":"그렇게 버둥거리니까...... 나도 모르게 손이 거칠어졌잖아.","JPN":"そんなにあがいてしまうから……つい手荒なことをしてしまったじゃない。","ENG":"With you wriggling around like that... you forced me to get a little rough.","TWN":"你這樣掙扎……我就不知不覺下手重了些。"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_NULL","text":{"KOREA":"그래도 불안해 하지 마렴.","JPN":"でも不安に思わないで。","ENG":"There's no need to be anxious though.","TWN":"但不用擔心。"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_NULL","text":{"KOREA":"자아, 이 팔은 어때 보이니.","JPN":"さあ、この腕はどう見える？","ENG":"How does this arm look?","TWN":"來，你看這只胳膊如何。"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_NULL","text":{"KOREA":"겁없이 나한테 덤벼들던 용병한테서 받아 왔단다.","JPN":"身の程知らずの分際で私に襲いかかってきた傭兵からもらってきたものよ。","ENG":"I got it from a mercenary that had the gall to attack me.","TWN":"這是從不知死活敢挑戰我的傭兵身上拿來的。"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_NULL","text":{"KOREA":"지금부터 너한테 어울리게...... 마음에 쏙 들 만큼 아주 아름다운 형태로......","JPN":"今からお前に似合う……見惚れてしまうほどとても美しい形に……","ENG":"I'll get it perfect, just for you... You'll love how beautiful it is...","TWN":"從現在開始，我會用最合適的……最美的形態，讓你滿意的……"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_NULL","text":{"KOREA":"재조립해 줄게.","JPN":"組み直してあげる。","ENG":"... once it's been reassembled with you.","TWN":"重新為你組裝。"},"stage":{"bg":"SS_SHADOW_03","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};